import ssl
import ipaddress
import re

def _hostname_match(hostname, pattern):
    """Match hostname against a pattern as used in certificate SAN/CN."""
    if not pattern:
        return False

    # Normalize both to lowercase
    hostname = hostname.lower()
    pattern = pattern.lower()

    # If no wildcard, direct comparison
    if '*' not in pattern:
        return hostname == pattern

    # Wildcard matching per RFC 6125
    # Wildcard only allowed in leftmost label
    if pattern.startswith('*.'):
        # Pattern must have at least two labels
        if pattern.count('.') < 1:
            return False

        # Check hostname has at least as many labels
        pattern_suffix = pattern[2:]  # Remove '*.' 

        # Hostname must have at least the same suffix
        if not hostname.endswith(pattern_suffix):
            return False

        # Hostname must not be just the suffix (e.g., 'example.com' vs '*.example.com')
        hostname_without_suffix = hostname[:-len(pattern_suffix)]
        if hostname_without_suffix[-1] != '.':
            return False

        # The leftmost label of hostname should not be empty
        leftmost_label = hostname_without_suffix[:-1]
        if not leftmost_label:
            return False

        # And the hostname should have exactly one more label than the pattern suffix
        if hostname.count('.') != pattern.count('.'):
            return False

        return True

